 1	import React, { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { modelToGroupVersionKind, modelToRef } from '@kubevirt-ui/kubevirt-api/console';
 5	import {
 6	  k8sPatch,
 7	  K8sResourceCommon,
 8	  K8sVerb,
 9	  useAccessReview,
10	  useK8sWatchResource,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import {
13	  Button,
14	  EmptyState,
15	  EmptyStateActions,
16	  EmptyStateFooter,
17	  EmptyStateHeader,
18	  Tooltip,
19	} from '@patternfly/react-core';
20	import { useLastNamespacePath } from '@utils/hooks/useLastNamespacePath';
21	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
22	import { MultiNetworkPolicyModel } from '@utils/models';
23	import { NetworkConfigModel } from '@views/nads/form/utils/constants';
24	
25	import '@styles/list-management-group.scss';
26	
27	const EnableMultiPage: FC = () => {
28	  const { t } = useNetworkingTranslation();
29	  const lastNamespacePath = useLastNamespacePath();
30	  const navigate = useNavigate();
31	
32	  const [networkClusterConfig, loaded] = useK8sWatchResource<K8sResourceCommon & { spec: any }>({
33	    groupVersionKind: modelToGroupVersionKind(NetworkConfigModel),
34	    name: 'cluster',
35	  });
36	
37	  const [canPatchConfig] = useAccessReview({
38	    group: NetworkConfigModel.apiGroup,
39	    resource: NetworkConfigModel.plural,
40	    verb: 'patch' as K8sVerb,
41	  });
42	
43	  const enableMultiNetworkPolicy = () => {
44	    k8sPatch({
45	      data: [
46	        {
47	          op: 'replace',
48	          path: '/spec/disableMultiNetwork',
49	          value: false,
50	        },
51	        {
52	          op: 'replace',
53	          path: '/spec/useMultiNetworkPolicy',
54	          value: true,
55	        },
56	      ],
57	      model: NetworkConfigModel,
58	      resource: networkClusterConfig,
59	    }).then(() => {
60	      navigate(`/k8s/${lastNamespacePath}/${modelToRef(MultiNetworkPolicyModel)}`);
61	    });
62	  };
63	
64	  const EnableButton = (
65	    <Button isDisabled={!loaded || !canPatchConfig} onClick={enableMultiNetworkPolicy}>
66	      {t('Enable {{kind}}', { kind: MultiNetworkPolicyModel.labelPlural })}
67	    </Button>
68	  );
69	
70	  return (
71	    <EmptyState>
72	      <EmptyStateHeader
73	        headingLevel="h4"
74	        titleText={t('{{kind}} disabled', { kind: MultiNetworkPolicyModel.labelPlural })}
75	      />
76	      <EmptyStateFooter>
77	        <EmptyStateActions>
78	          {canPatchConfig ? (
79	            EnableButton
80	          ) : (
81	            <Tooltip
82	              content={t('Cluster administrator permissions are required to enable this feature.')}
83	            >
84	              <span>{EnableButton}</span>
85	            </Tooltip>
86	          )}
87	        </EmptyStateActions>
88	      </EmptyStateFooter>
89	    </EmptyState>
90	  );
91	};
92	
93	export default EnableMultiPage;

